#include <bits/stdc++.h>
using namespace std;

const int mod=2004;

int n,a,b,m[15],ans;

int C(int n,int m){
    if(n<0 || n<m) return 0;
    long long fac=1,res=1;
    for(int i=2;i<=m;i++)
        fac*=i;
    for(int i=n-m+1;i<=n;i++)
        res=1ll*res*i%(mod*fac);
    return res/fac%mod;
}

int main(){
    scanf("%d%d%d",&n,&a,&b);
    for(int i=1;i<=n;i++)
        scanf("%d",&m[i]);
    for(int i=0;i<1<<n;i++){
        int cnt=0,sum=0;
        for(int j=1;j<=n;j++)
            if((i>>j-1)&1)
                cnt++,sum+=m[j]+1;
        if(cnt%2==0) ans=(ans+C(b-sum+n,n)-C(a-sum-1+n,n))%mod;
        else ans=(ans-C(b-sum+n,n)+C(a-sum-1+n,n))%mod;
    }
    printf("%d",(ans+mod)%mod);
    return 0;
}
